INSERT INTO public.managed_email_types (email_key, name, category, default_subject, default_body_html, description, is_active)
VALUES
  ('woo_merchant_welcome', 'WooCommerce Merchant Welcome', 'merchant', 'Welcome to Woo for Kang — Your API Credentials', '<p>Hello <strong>{{store_name}}</strong> team,</p><p>Welcome to Woo for Kang! Your WooCommerce store has been successfully registered with Kang Open Banking.</p><p><strong>Your API Credentials (keep them secure):</strong></p><ul><li><strong>API Key:</strong> {{api_key}}</li><li><strong>Client Secret:</strong> {{client_secret}}</li><li><strong>Webhook Secret:</strong> {{webhook_secret}}</li></ul><p><strong>Webhook URL (auto-configured):</strong> {{webhook_url}}</p><p><strong>Next Steps:</strong></p><ol><li>Copy your API credentials above</li><li>In WordPress admin, go to WooCommerce → Settings → Payments</li><li>Enable "Kang Open Banking" and paste your credentials</li><li>Configure which payment methods you want to accept</li><li>Test with a small transaction</li></ol><p>Need help? Contact us at <a href="mailto:support@kangopenbanking.com">support@kangopenbanking.com</a></p>', 'Welcome email sent when a WooCommerce merchant registers', true),
  ('woo_payment_completed', 'WooCommerce Payment Completed', 'merchant', 'Payment Received — WooCommerce Order #{{order_id}}', '<p>Hello <strong>{{store_name}}</strong>,</p><p>Great news! A payment of <strong>{{amount}}</strong> has been successfully received for WooCommerce Order <strong>#{{order_id}}</strong>.</p><p><strong>Payment Details:</strong></p><ul><li><strong>Amount:</strong> {{amount}}</li><li><strong>Payment Method:</strong> {{payment_method}}</li><li><strong>Transaction Ref:</strong> {{transaction_ref}}</li></ul><p>The order status has been updated automatically in your WooCommerce dashboard.</p>', 'Sent to merchant when a WooCommerce payment is completed', true),
  ('woo_payment_failed', 'WooCommerce Payment Failed', 'merchant', 'Payment Failed — WooCommerce Order #{{order_id}}', '<p>Hello <strong>{{store_name}}</strong>,</p><p>Unfortunately, a payment of <strong>{{amount}}</strong> for WooCommerce Order <strong>#{{order_id}}</strong> has failed.</p><p><strong>Details:</strong></p><ul><li><strong>Amount:</strong> {{amount}}</li><li><strong>Payment Method:</strong> {{payment_method}}</li><li><strong>Transaction Ref:</strong> {{transaction_ref}}</li><li><strong>Error:</strong> {{error_message}}</li></ul><p>The customer may need to retry the payment. Please check your WooCommerce dashboard for details.</p>', 'Sent to merchant when a WooCommerce payment fails', true),
  ('woo_refund_processed', 'WooCommerce Refund Processed', 'merchant', 'Refund Processed — WooCommerce Order #{{order_id}}', '<p>Hello <strong>{{store_name}}</strong>,</p><p>A refund of <strong>{{amount}}</strong> has been processed for WooCommerce Order <strong>#{{order_id}}</strong>.</p><p><strong>Refund Details:</strong></p><ul><li><strong>Amount Refunded:</strong> {{amount}}</li><li><strong>Payment Method:</strong> {{payment_method}}</li><li><strong>Transaction Ref:</strong> {{transaction_ref}}</li></ul><p>The order status has been updated in your WooCommerce dashboard.</p>', 'Sent to merchant when a WooCommerce refund is processed', true)
